const now = new Date();
const dayOfWeek = now.getDay();
const daysFromMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
const monday = new Date(now);
monday.setDate(now.getDate() - daysFromMonday);
monday.setHours(0, 0, 0, 0);

const friday = new Date(monday);
friday.setDate(monday.getDate() + 4);

const today = now.toISOString().split('T')[0];
const weekStart = monday.toISOString().split('T')[0];
const weekEnd = friday.toISOString().split('T')[0];

const startOfYear = new Date(now.getFullYear(), 0, 1);
const weekNum = Math.ceil(((now - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
const weekLabel = `${now.getFullYear()}-W${String(weekNum).padStart(2, '0')}`;

return [{ json: { today, weekStart, weekEnd, weekLabel } }];

const dateInfo = $('今週の日付計算').first().json;
const weekStart = dateInfo.weekStart;
const weekEnd = dateInfo.weekEnd;
const weekLabel = dateInfo.weekLabel;
const today = dateInfo.today;

// GitHub APIのレスポンスは配列か単一アイテムかを両方対応
let allFiles;
if (Array.isArray(items[0].json)) {
  allFiles = items[0].json;
} else {
  allFiles = items.map(item => item.json);
}

// 今週のファイルをフィルタリング
const weekFiles = allFiles.filter(file => {
  const dateMatch = file.name && file.name.match(/^(\d{4}-\d{2}-\d{2})/);
  if (!dateMatch) return false;
  const fileDate = dateMatch[1];
  return fileDate >= weekStart && fileDate <= weekEnd;
});

const articleList = weekFiles.length > 0
  ? weekFiles.map(f => `- ${f.name}`).join('\n')
  : '（今週のデイリー記事はまだありません）';

const prompt = `あなたはAI×バックオフィス専門メディアの編集者です。

今週（${weekStart}〜${weekEnd}）に生成されたデイリー記事一覧：
${articleList}

以下の条件で週次深掘り記事を3000字以上で生成してください。

【テーマ選定基準】
- 一人社長・経理担当者が最も実務で活用できるAI×バックオフィステーマ
- AI自動化・会計DX・業務効率化に関連するテーマを優先
- 具体的なアクションに落とし込める内容

【出力形式】コードブロック不要。以下の形式のみで出力：
---
title: "【週次深掘り】（タイトル）"
date: "${today}T09:00:00+09:00"
draft: false
type: "weekly"
summary: "（150字以内の要約）"
image: "https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&q=80"
week: "${weekLabel}"
impact_score: 5
tags: ["タグ1", "タグ2", "タグ3"]
---

## （導入：なぜ今このテーマが重要か）
（300字以上で時代背景と課題を説明）

## （分析①：具体的な内容と深掘り）
（500字以上。{{< marker >}}重要ポイント{{< /marker >}}を2〜3箇所使用）

## （分析②：実務への応用）
（500字以上）

## （分析③：比較・選択基準など）
（400字以上）

## 今週の結論：あなたへのアクションプラン
1. **アクション1**——詳細な説明
