※マネーフォワードに言及する場合は {{< affiliate-mf "マネーフォワード クラウド会計" >}} を使用
※freeeに言及する場合は {{< affiliate-freee "freee会計" >}} を使用

【制約】合計3000字以上。必ず日本語で出力。`;

return [{ json: { prompt, weekLabel, today, weekStart, weekEnd, fileCount: weekFiles.length } }];

const responseText = items[0].json.candidates[0].content.parts[0].text;
const metaInfo = $('今週記事フィルタ＆プロンプト作成').first().json;
const today = metaInfo.today;
const weekLabel = metaInfo.weekLabel;

let articleBody = responseText.trim();
let frontMatterYaml = '';
let bodyContent = articleBody;

if (articleBody.startsWith('---')) {
  const firstClose = articleBody.indexOf('\n---', 3);
  if (firstClose > 0) {
    frontMatterYaml = articleBody.substring(3, firstClose).trim();
    bodyContent = articleBody.substring(firstClose + 4).trim();
  }
} else if (articleBody.startsWith('```')) {
  const firstNewline = articleBody.indexOf('\n');
  const codeEnd = articleBody.indexOf('\n```', firstNewline);
  const dashEnd = articleBody.indexOf('\n---', firstNewline);
  let endPos = -1;
  if (codeEnd > 0 && (dashEnd < 0 || codeEnd < dashEnd)) {
    endPos = codeEnd;
  } else if (dashEnd > 0) {
    endPos = dashEnd;
  }
  if (endPos > 0) {
    frontMatterYaml = articleBody.substring(firstNewline + 1, endPos).trim();
    bodyContent = articleBody.substring(endPos + 4).trim();
  }
}

const titleMatch = frontMatterYaml.match(/title:\s*"?([^"\n]+)"?/);
const title = titleMatch
  ? titleMatch[1].trim().replace(/"/g, '\\"')
  : `【週次深掘り】週次レポート ${weekLabel}`;

const dateMatch = frontMatterYaml.match(/date:\s*"?([^"\n]+)"?/);
const articleDate = dateMatch ? dateMatch[1].trim() : `${today}T09:00:00+09:00`;

const summaryMatch = frontMatterYaml.match(/summary:\s*"?([^"\n]+)"?/);
const summary = summaryMatch ? summaryMatch[1].replace(/"/g, '\\"') : '';

const imageMatch = frontMatterYaml.match(/image:\s*"?([^"\n]+)"?/);
const image = imageMatch ? imageMatch[1].trim() : 'https://images.unsplash.com/photo-1554224155-6726b3ff858f?w=1200&q=80';

const tagsMatch = frontMatterYaml.match(/tags:\s*(\[.+\])/);
const tags = tagsMatch ? tagsMatch[1] : '["バックオフィスDX", "AI活用", "週次深掘り"]';

const content = `---\ntitle: "${title}"\ndate: "${articleDate}"\ndraft: false\ntype: "weekly"\nsummary: "${summary}"\nimage: "${image}"\nweek: "${weekLabel}"\nimpact_score: 5\ntags: ${tags}\n---\n\n${bodyContent}`;

const filename = `${today}-weekly-${Date.now()}.md`;
return [{ json: { filename, content, today, weekLabel } }];

const article = items[0].json;
const filePath = `content/weekly/${article.filename}`;
const contentBase64 = Buffer.from(article.content, 'utf-8').toString('base64');
return [{ json: { ...article, filePath, contentBase64 } }];

const article = $('配信データ準備').first().json;
const shaResponse = items[0].json;
const sha = shaResponse.sha || null;

const commitBody = {
  message: `Add weekly deep-dive article: ${article.filename}`,
  content: article.contentBase64
};
if (sha) commitBody.sha = sha;

return [{ json: { ...article, sha, commitBodyJson: JSON.stringify(commitBody) } }];

