const weekLabel = $('Hugo Markdown整形').first().json.weekLabel;
console.log(`週次記事コミット完了: ${filename}`);
return [{ json: { status: 'success', message: `週次深掘り記事 ${weekLabel} を生成・コミットしました`, filename } }];
